function OrderTracker() {
  const [orders, setOrders] = React.useState([
    { id: 'ORD-7281', store: 'Amazon', status: 2, steps: ['Ordered', 'Shipped', 'Out for delivery', 'Delivered'], items: ['Wireless Mouse', 'USB-C Cable'] },
    { id: 'ORD-9102', store: 'Best Buy', status: 1, steps: ['Ordered', 'Shipped', 'Out for delivery', 'Delivered'], items: ['Monitor Stand'] }
  ]);
  const [newStore, setNewStore] = React.useState('');
  const [newItems, setNewItems] = React.useState('');

  function addOrder() {
    if (!newStore.trim()) return;
    const id = 'ORD-' + Math.floor(1000 + Math.random() * 9000);
    setOrders([...orders, { id, store: newStore, status: 0, steps: ['Ordered', 'Shipped', 'Out for delivery', 'Delivered'], items: newItems.split(',').map(s => s.trim()).filter(Boolean) }]);
    setNewStore('');
    setNewItems('');
  }

  function advanceStatus(idx) {
    setOrders(orders.map((o, i) => i === idx ? { ...o, status: Math.min(o.steps.length - 1, o.status + 1) } : o));
  }

  function removeOrder(idx) {
    setOrders(orders.filter((_, i) => i !== idx));
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>Order Tracker</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input placeholder="Store" value={newStore} onChange={e => setNewStore(e.target.value)} style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <input placeholder="Items (comma sep)" value={newItems} onChange={e => setNewItems(e.target.value)} style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <button onClick={addOrder} style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: '#2563eb', color: '#fff', fontSize: 13, cursor: 'pointer' }}>Add</button>
      </div>
      <div style={{ flex: 1, overflowY: 'auto' }}>
        {orders.map((order, i) => (
          <div key={i} style={{ marginBottom: 14, padding: 12, borderRadius: 8, background: '#f8f9fa' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span style={{ fontWeight: 700, fontSize: 13, color: '#2563eb' }}>{order.id}</span>
                <span style={{ fontSize: 13, color: '#444' }}>{order.store}</span>
              </div>
              <div style={{ display: 'flex', gap: 6 }}>
                <button onClick={() => advanceStatus(i)} style={{ padding: '4px 10px', borderRadius: 6, border: 'none', background: '#2563eb', color: '#fff', fontSize: 12, cursor: 'pointer' }}>Next</button>
                <button onClick={() => removeOrder(i)} style={{ background: 'transparent', border: 'none', color: '#999', cursor: 'pointer', fontSize: 16 }}>x</button>
              </div>
            </div>
            <div style={{ fontSize: 12, color: '#666', marginBottom: 10 }}>{order.items.join(', ')}</div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 0 }}>
              {order.steps.map((step, si) => (
                <React.Fragment key={si}>
                  <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', flex: 1 }}>
                    <div style={{ width: 14, height: 14, borderRadius: '50%', background: si <= order.status ? '#2563eb' : '#d1d5db', border: '2px solid ' + (si <= order.status ? '#2563eb' : '#d1d5db'), transition: 'all 0.3s' }} />
                    <div style={{ fontSize: 10, color: si <= order.status ? '#2563eb' : '#9ca3af', marginTop: 4, textAlign: 'center' }}>{step}</div>
                  </div>
                  {si < order.steps.length - 1 && (
                    <div style={{ flex: 1, height: 2, background: si < order.status ? '#2563eb' : '#e5e7eb', marginTop: -14 }} />
                  )}
                </React.Fragment>
              ))}
            </div>
          </div>
        ))}
        {orders.length === 0 && <div style={{ textAlign: 'center', color: '#999', fontSize: 13, padding: 20 }}>No orders to track.</div>}
      </div>
    </div>
  );
}
render(<OrderTracker/>);
